// Defina o type FORA da classe
type AtributoNome = 'forca' | 'destreza' | 'constituicao' | 'inteligencia' | 'sabedoria' | 'carisma';

import { Component } from '@angular/core';
import { FormsModule } from '@angular/forms';


@Component({
  selector: 'app-criar-personagem',
  templateUrl: './criar-personagem.component.html',
  styleUrls: ['./criar-personagem.component.css']
})
export class CriarPersonagemComponent {
  etapa: number = 1;
  metodoAtributos: 'rolagem' | 'manual' | null = null;

  atributoNomes: Array<'forca' | 'destreza' | 'constituicao' | 'inteligencia' | 'sabedoria' | 'carisma'> = [
    'forca',
    'destreza',
    'constituicao',
    'inteligencia',
    'sabedoria',
    'carisma'
  ];

  racas = [
    { nome: 'Humano', img: undefined },
    { nome: 'Elfo', img: undefined },
    { nome: 'Anão', img: undefined },
    { nome: 'Halfling', img: undefined },
    { nome: 'Gnomo', img: undefined },
    { nome: 'Meio-Orc', img: undefined },
    { nome: 'Meio-Elfo', img: undefined },
    { nome: 'Draconato', img: undefined },
    { nome: 'Tiefling', img: undefined }
  ];
  classes = [
    { nome: 'Bárbaro', img: undefined },
    { nome: 'Bardo', img: undefined },
    { nome: 'Bruxo', img: undefined },
    { nome: 'Clérigo', img: undefined },
    { nome: 'Druida', img: undefined },
    { nome: 'Feiticeiro', img: undefined },
    { nome: 'Guerreiro', img: undefined },
    { nome: 'Ladino', img: undefined },
    { nome: 'Mago', img: undefined },
    { nome: 'Monge', img: undefined },
    { nome: 'Paladino', img: undefined },
    { nome: 'Patrulheiro', img: undefined }
  ];

  personagem = {
    raca: '',
    classe: '',
    atributos: {
      forca: 0,
      destreza: 0,
      constituicao: 0,
      inteligencia: 0,
      sabedoria: 0,
      carisma: 0
    }
  };

  selecionarRaca(raca: string) {
    this.personagem.raca = raca;
    this.etapa = 2;
  }

  selecionarClasse(classe: string) {
    this.personagem.classe = classe;
    this.etapa = 3;
  }

  escolherMetodoAtributos(metodo: 'rolagem' | 'manual') {
    this.metodoAtributos = metodo;
    if (metodo === 'rolagem') {
      this.rolarAtributos();
    }
    this.etapa = 4;
  }

  usarDistribuicaoPontos() {
    this.metodoAtributos = 'manual';
  }

  definirAtributo(atributo: AtributoNome, valor: number) {
    this.personagem.atributos[atributo] = valor;
  }

  rolarAtributos() {
    this.metodoAtributos = 'rolagem';
    this.personagem.atributos = {
        forca: this.rolarDado(),
        destreza: this.rolarDado(),
        constituicao: this.rolarDado(),
        inteligencia: this.rolarDado(),
        sabedoria: this.rolarDado(),
        carisma: this.rolarDado()
    };
  }

  rolarDado(): number {
    let rolagens = [
      Math.floor(Math.random() * 6) + 1,
      Math.floor(Math.random() * 6) + 1,
      Math.floor(Math.random() * 6) + 1,
      Math.floor(Math.random() * 6) + 1
    ];
    rolagens.sort((a, b) => a - b).shift();
    return rolagens.reduce((a, b) => a + b, 0);
  }

  finalizarPersonagem() {
    this.etapa = 4;
  }
  finalizarCriacao() {
    console.log("Personagem criado com sucesso:", this.personagem);
    alert("Personagem criado com sucesso! Confira o console para detalhes.");
}

  voltarEtapa() {
    if (this.etapa! > 1) {
      if (this.etapa! === 4) {
        this.metodoAtributos = null;
      }
      this.etapa!--;
    }
  }
}
<app-header></app-header>
<section>
    <div class="criacao-personagem">
        <!-- Escolha de Raça -->
        <div *ngIf="etapa === 1" class="etapa">
            <h2>Escolha sua Raça</h2>
            <div class="opcoes">
                <div *ngFor="let raca of racas" (click)="selecionarRaca(raca.nome)" class="opcao">
                    <img [src]="raca.img" [alt]="raca.nome">
                    <p>{{ raca.nome }}</p>
                </div>
            </div>
        </div>

        <!-- Escolha de Classe -->
        <div *ngIf="etapa === 2" class="etapa">
            <button (click)="voltarEtapa()" class="btn-voltar">← Voltar</button>
            <h2>Escolha sua Classe</h2>
            <div class="opcoes">
                <div *ngFor="let classe of classes" (click)="selecionarClasse(classe.nome)" class="opcao">
                    <img [src]="classe.img" [alt]="classe.nome">
                    <p>{{ classe.nome }}</p>
                </div>
            </div>
        </div>

        <!-- Escolha de Atributos -->
        <div *ngIf="etapa === 3" class="etapa">
            <button (click)="voltarEtapa()" class="btn-voltar">← Voltar</button>
            <h2>Defina seus Atributos</h2>

            <div class="opcoes">
                <button (click)="rolarAtributos()">Rolar Atributos 🎲</button>
                <button (click)="usarDistribuicaoPontos()">Distribuir Manualmente</button>
            </div>

            <div *ngIf="metodoAtributos === 'rolagem'">
                <div *ngFor="let atributo of atributoNomes" class="atributo">
                    <span>{{ atributo }}: {{ personagem.atributos[atributo] }}</span>
                </div>
            </div>

            <div *ngIf="metodoAtributos === 'manual'">
                <div *ngFor="let atributo of atributoNomes" class="atributo">
                    <label>{{ atributo }}:</label>
                    <input type="number" [(ngModel)]="personagem.atributos[atributo]" min="1" max="15">
                </div>
            </div>

        </div>
    </div>
    <!-- Resumo do Personagem -->
<div *ngIf="etapa === 4" class="etapa">
    <button (click)="voltarEtapa()" class="btn-voltar">← Voltar</button>
    <h2>Resumo do Personagem</h2>

    <div class="resumo">
        <p><strong>Raça:</strong> {{ personagem.raca }}</p>
        <p><strong>Classe:</strong> {{ personagem.classe }}</p>
        <p><strong>Atributos:</strong></p>
        <ul>
            <li *ngFor="let atributo of atributoNomes">
                {{ atributo }}: {{ personagem.atributos[atributo] }}
            </li>
        </ul>
    </div>

    <button (click)="finalizarCriacao()" class="btn-finalizar">Finalizar Criação</button>
</div>
</section>
<app-footer></app-footer>
